using UnityEngine;
public class ShapeSystem : MonoBehaviour
{
    [SerializeField] private OrderManager orderManager;
    public ShapeType TargetShapeType { get; private set; }
    public float TargetMouth { get; private set; }
    public float TargetNeck { get; private set; }
    public float TargetShoulder { get; private set; }
    public float TargetBelly { get; private set; }
    public float TargetFoot { get; private set; }
    public bool HasTarget { get; private set; }
    public float ShapeMatch { get; private set; }
    private void Awake()
    {
        LoadTargetFromCurrentOrder();
    }
    public bool LoadTargetFromCurrentOrder()
    {
        HasTarget = false;

        if (orderManager == null)
        {
            return false;
        }

        OrderData currentOrder = orderManager.GetCurrentOrder();
        if (currentOrder == null || currentOrder.shapeRecipe == null)
        {
            return false;
        }

        ShapeRecipeData recipe = currentOrder.shapeRecipe;
        TargetShapeType = recipe.shapeType;
        TargetMouth = recipe.mouth;
        TargetNeck = recipe.neck;
        TargetShoulder = recipe.shoulder;
        TargetBelly = recipe.belly;
        TargetFoot = recipe.foot;
        HasTarget = true;
        return true;
    }
    public float CalculateParameterError(float playerValue, float targetValue)
    {
        return Mathf.Abs(Mathf.Clamp01(playerValue) - Mathf.Clamp01(targetValue));
    }
    public float CalculateMouthError(float playerValue)
    {
        return CalculateParameterError(playerValue, TargetMouth);
    }
    public float CalculateNeckError(float playerValue)
    {
        return CalculateParameterError(playerValue, TargetNeck);
    }
    public float CalculateShoulderError(float playerValue)
    {
        return CalculateParameterError(playerValue, TargetShoulder);
    }
